mapper.select:
select * from (
select distinct kb.id as id,kb.title as title ,kc.name as ctName ,csu.real_name as createUser,
kb.pub_time as pub_time,kc.sw_id as swId,ku.readCount
FROM kb_user_label kul
left join kb_basic_label kbl on kul.label_id = kbl.l_id
left join kb_basic kb on kbl.b_id = kb.id
left join castle_sys_user csu on kb.auth = csu.id
left join kb_category kc on kb.category_id = kc.id
left join (select count(1) as readCount,b_id from kb_basic_user where type= 1
group by b_id) ku on kb.id = ku.b_id

	kb.is_deleted = 2
	and kul.user_id = #{kbBaseShowDto.createUser}
	and kb.auth != #{kbBaseShowDto.createUser}
	and kb.status = 1

		and kul.label_id in (

			#{labelId}

		)


		and kb.category_id in (

			#{kcId}

		)


		and kc.sw_id in (

			#{swId}

		)


		and kb.category_id in (

			#{id}

		)


		and kb.title like concat('%',#{kbBaseShowDto.title},'%')


		and kb.pub_time like concat(#{kbBaseShowDto.fromTime},'%')


union
select distinct kb.id as id,kb.title as title ,kc.name as ctName ,csu.real_name as createUser,
